import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Marketer Hub Overview","description":"","frontmatter":{"title":"Marketer Hub Overview","slug":"marketer-hub-overview"},"headers":[],"relativePath":"marketer-hub/marketer-hub-overview.md","filePath":"marketer-hub/marketer-hub-overview.md"}'),n={name:"marketer-hub/marketer-hub-overview.md"};function i(s,e,p,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>Welcome to Branch’s <strong>Marketer Hub</strong>, your place to find resources for marketers leveraging Branch&#39;s Growth Platform to drive engagement, optimize campaign performance, and activate customers across channels.</p><h2 id="what-is-marketer-hub" tabindex="-1">What is Marketer Hub? <a class="header-anchor" href="#what-is-marketer-hub" aria-label="Permalink to &quot;What is Marketer Hub?&quot;">​</a></h2><p>Marketer Hub is a dedicated documentation workspace designed for marketers, growth teams, and campaign managers using Branch. Whether you&#39;re creating personalized link campaigns, measuring ad performance, or driving app adoption, you&#39;ll find guides, best practices, and insights here to help drive your success.</p><p>This hub focuses on the marketer experience, from campaign setup and optimization to analytics and reporting, without requiring technical implementation or coding knowledge.</p><h2 id="what-s-inside" tabindex="-1">What’s inside <a class="header-anchor" href="#what-s-inside" aria-label="Permalink to &quot;What’s inside&quot;">​</a></h2><p><a href="./get-started-marketer-hub.html">Get Started</a></p><p>New to Branch? Start here to understand the basics and get oriented with the platform&#39;s marketer-focused features.</p><p><a href="./attribution-methodology.html">Attribution and Methodology</a></p><p>Understand how Branch measures user interactions and conversions across channels to help you make data-driven decisions about campaign performance.</p><p><a href="./new-branch.html">New Branch</a></p><p>Learn about the latest platform updates, features, and improvements. Please note that these features are being rolled out to customers in stages.</p><p><a href="./dashboard-exports-index.html">Reports and Exports</a></p><p>Access detailed analytics and export campaign data to measure performance, demonstrate ROI, and inform strategic decisions.</p><p><a href="./branch-links.html">Links</a></p><p>Use Branch&#39;s deep linking technology to create seamless user experiences that drive engagement and conversions across web, mobile, email, and social channels.</p><p><a href="./journeys.html">Journeys</a></p><p>Implement smart banners that intelligently move users from mobile web to app, driving adoption on your highest-performing platform.</p><p><a href="./email.html">Email and SMS</a></p><p>Integrate Branch Links into your email campaigns to track performance and deliver personalized experiences that route users to the right destination.</p><p><a href="./deepviews.html">Deepviews</a></p><p>Create mobile web previews that showcase app content and encourage installation before users even download your app.</p><p><a href="./seo-and-aio.html">SEO and AIO</a></p><p>Track and attribute organic traffic from search engines and AI chat agents.</p><p><a href="./ads.html">Ads</a></p><p>Set up and optimize paid advertising campaigns across platforms. Includes support for features like cost data integration (ROI Hub) and measurement on household devices.</p><p><a href="./skadnetwork-ios-versions.html">SKAdNetwork and iOS</a></p><p>Navigate Apple&#39;s privacy framework to maintain effective measurement and attribution for iOS campaigns.</p><p><a href="./advanced-data-feeds.html">Data Feeds</a></p><p>Connect Branch data to your analytics tools, warehouses, and business intelligence platforms for comprehensive reporting. Set up webhooks to export install and down-funnel event data as it occurs.</p><p><a href="./liveview-index.html">Liveview</a></p><p>Monitor event and webhook activity in real-time to test your configurations and make quick optimizations.</p><h2 id="how-to-navigate" tabindex="-1">How to navigate <a class="header-anchor" href="#how-to-navigate" aria-label="Permalink to &quot;How to navigate&quot;">​</a></h2><p>Use the left sidebar to browse topics, or use the search function (CMD+K) to quickly find specific information. Each section contains detailed guides, step-by-step instructions, and best practices to help you get the most from Branch&#39;s platform.</p><p>Article folders are organized primarily by feature, making it easy to compare what you see in Branch with the structure of Marketer Hub.</p><h2 id="need-developer-resources" tabindex="-1">Need developer resources? <a class="header-anchor" href="#need-developer-resources" aria-label="Permalink to &quot;Need developer resources?&quot;">​</a></h2><p>While Marketer Hub focuses on campaign creation, optimization, and analytics, some implementations may require technical support. For SDK integration, API documentation, and developer guides, please visit <a href="./get-started-developer-hub.html">Developer Hub</a>.</p>',36)])])}const u=a(n,[["render",i]]);export{m as __pageData,u as default};
